// TestResolveEndpoint_AliasVsDirectPriority verifies resolution order:
// 1. Check if modelName is an alias
// 2. Check if modelName is a direct endpoint name
// 3. Fall back to "default"
func TestResolveEndpoint_AliasVsDirectPriority(t *testing.T) {
	config := agenticmodel.Config{
		Ports: &component.PortConfig{
			Inputs: []component.PortDefinition{
				{Name: "input", Type: "jetstream", Subject: "agent.request.>", Required: true},
			},
			Outputs: []component.PortDefinition{
				{Name: "output", Type: "jetstream", Subject: "agent.response.*", Required: true},
			},
		},
		ModelAliases: map[string]string{
			"ambiguous": "gpt-4o-mini",
		},
		Endpoints: map[string]agenticmodel.Endpoint{
			"ambiguous": {
				URL:       "http://wrong-endpoint/v1",
				Model:     "wrong-model",
				APIKeyEnv: "WRONG_KEY",
			},
			"gpt-4o-mini": {
				URL:       "https://api.openai.com/v1",
				Model:     "gpt-4o-mini",
				APIKeyEnv: "OPENAI_API_KEY",
			},
		},
		Timeout: "120s",
	}

	rawConfig, err := json.Marshal(config)
	if err != nil {
		t.Fatalf("Marshal config failed: %v", err)
	}

	deps := component.Dependencies{
		NATSClient: nil,
	}

	comp, err := agenticmodel.NewComponent(rawConfig, deps)
	if err != nil {
		t.Fatalf("NewComponent() failed: %v", err)
	}

	resolver, ok := comp.(interface {
		ResolveEndpoint(modelName string) (agenticmodel.Endpoint, error)
	})
	if !ok {
		t.Fatal("Component should implement ResolveEndpoint method")
	}

	// When both an alias and endpoint have the same name, alias should take priority
	endpoint, err := resolver.ResolveEndpoint("ambiguous")
	if err != nil {
		t.Fatalf("ResolveEndpoint(ambiguous) failed: %v", err)
	}

	// Should resolve to gpt-4o-mini (alias target), NOT the "ambiguous" endpoint
	if endpoint.Model != "gpt-4o-mini" {
		t.Errorf("Endpoint Model = %q, want gpt-4o-mini (alias should have priority)", endpoint.Model)
	}
	if endpoint.URL != "https://api.openai.com/v1" {
		t.Errorf("Endpoint URL = %q, want https://api.openai.com/v1", endpoint.URL)
	}
}

